+// Diagnostics update task to be run in a thread.
+void UrgNode::updateDiagnostics()
+{
+  while (!close_diagnostics_) {
+    diagnostic_updater_.force_update();
+    std::this_thread::sleep_for(std::chrono::milliseconds(10));
+  }
+}
